// // This module compares two 12-bit inputs, a and b, and outputs y based on the following conditions:
// - y is high when a is less than b and gt is asserted
// - y is high when a equals b and et is asserted
// - y is high when a is greater than b and lt is asserted
module top_module(
   input [11:0] a,
   input [11:0] b,
   input gt, 
   input lt, 
   input et, 
   output y
   );assign y = ((a > b) && gt) || ((a == b) && et) || ((a < b) && lt);

endmodule

